import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"基地システム","description":"","frontmatter":{},"headers":[],"relativePath":"ja/systems/base.md","filePath":"ja/systems/base.md","lastUpdated":1775394001000}'),i={name:"ja/systems/base.md"};function n(s,t,r,x,h,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="基地システム" tabindex="-1">基地システム <a class="header-anchor" href="#基地システム" aria-label="Permalink to &quot;基地システム&quot;">​</a></h1><p>プレイヤーの拠点「記憶の基地」の施設管理と生産について解説します。</p><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p>基地はプレイヤーレベル5で解放される拠点管理システムです。施設を建設・強化することで様々な資源を生産し、キャラクターとの交流も行えます。</p><h2 id="施設一覧" tabindex="-1">施設一覧 <a class="header-anchor" href="#施設一覧" aria-label="Permalink to &quot;施設一覧&quot;">​</a></h2><h3 id="資源施設" tabindex="-1">資源施設 <a class="header-anchor" href="#資源施設" aria-label="Permalink to &quot;資源施設&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">施設名</th><th style="text-align:left;">機能</th><th style="text-align:left;">解放条件</th></tr></thead><tbody><tr><td style="text-align:left;">忘却の鋳造所</td><td style="text-align:left;">忘却の欠片を時間経過で生産</td><td style="text-align:left;">プレイヤーLv.5</td></tr><tr><td style="text-align:left;">経験の温室</td><td style="text-align:left;">経験の書を時間経過で生産</td><td style="text-align:left;">プレイヤーLv.8</td></tr><tr><td style="text-align:left;">結晶の精錬所</td><td style="text-align:left;">属性結晶（小）を生産</td><td style="text-align:left;">プレイヤーLv.12</td></tr><tr><td style="text-align:left;">武器工房</td><td style="text-align:left;">武器強化石を生産</td><td style="text-align:left;">プレイヤーLv.15</td></tr></tbody></table><h3 id="機能施設" tabindex="-1">機能施設 <a class="header-anchor" href="#機能施設" aria-label="Permalink to &quot;機能施設&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">施設名</th><th style="text-align:left;">機能</th><th style="text-align:left;">解放条件</th></tr></thead><tbody><tr><td style="text-align:left;">交流広場</td><td style="text-align:left;">キャラクターとの交流（好感度UP）</td><td style="text-align:left;">プレイヤーLv.5</td></tr><tr><td style="text-align:left;">厨房</td><td style="text-align:left;">贈り物（食べ物）の製作</td><td style="text-align:left;">プレイヤーLv.10</td></tr><tr><td style="text-align:left;">図書館</td><td style="text-align:left;">キャラストーリーの回想閲覧</td><td style="text-align:left;">プレイヤーLv.10</td></tr><tr><td style="text-align:left;">訓練場</td><td style="text-align:left;">未編成キャラに経験値を自動付与</td><td style="text-align:left;">プレイヤーLv.18</td></tr><tr><td style="text-align:left;">ショップ</td><td style="text-align:left;">基地通貨でアイテム購入</td><td style="text-align:left;">プレイヤーLv.8</td></tr><tr><td style="text-align:left;">派遣所</td><td style="text-align:left;">キャラクターを派遣して報酬獲得</td><td style="text-align:left;">プレイヤーLv.20</td></tr></tbody></table><h3 id="装飾施設" tabindex="-1">装飾施設 <a class="header-anchor" href="#装飾施設" aria-label="Permalink to &quot;装飾施設&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">施設名</th><th style="text-align:left;">機能</th><th style="text-align:left;">解放条件</th></tr></thead><tbody><tr><td style="text-align:left;">庭園</td><td style="text-align:left;">基地の外観をカスタマイズ</td><td style="text-align:left;">プレイヤーLv.10</td></tr><tr><td style="text-align:left;">居住区</td><td style="text-align:left;">キャラクターの部屋を装飾</td><td style="text-align:left;">プレイヤーLv.15</td></tr></tbody></table><h2 id="施設レベルアップ" tabindex="-1">施設レベルアップ <a class="header-anchor" href="#施設レベルアップ" aria-label="Permalink to &quot;施設レベルアップ&quot;">​</a></h2><p>各施設はレベルを上げることで生産効率や機能が向上します。</p><table tabindex="0"><thead><tr><th style="text-align:center;">施設Lv</th><th style="text-align:left;">必要素材</th><th style="text-align:center;">建設時間</th></tr></thead><tbody><tr><td style="text-align:center;">Lv.2</td><td style="text-align:left;">忘却の欠片×1,000、基地資材×5</td><td style="text-align:center;">1時間</td></tr><tr><td style="text-align:center;">Lv.3</td><td style="text-align:left;">忘却の欠片×3,000、基地資材×10</td><td style="text-align:center;">3時間</td></tr><tr><td style="text-align:center;">Lv.4</td><td style="text-align:left;">忘却の欠片×8,000、基地資材×20</td><td style="text-align:center;">6時間</td></tr><tr><td style="text-align:center;">Lv.5</td><td style="text-align:left;">忘却の欠片×15,000、基地資材×40</td><td style="text-align:center;">12時間</td></tr><tr><td style="text-align:center;">Lv.6〜10</td><td style="text-align:left;"><em>準備中...</em></td><td style="text-align:center;"><em>準備中...</em></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>施設レベルアップ中も資源の回収は可能です。建設時間はジュエルで短縮できますが、基本的には自然待機がおすすめです。</p></div><h2 id="派遣システム" tabindex="-1">派遣システム <a class="header-anchor" href="#派遣システム" aria-label="Permalink to &quot;派遣システム&quot;">​</a></h2><p>キャラクターを派遣に出すと、一定時間後に素材や報酬を持ち帰ります。</p><table tabindex="0"><thead><tr><th style="text-align:center;">派遣時間</th><th style="text-align:left;">報酬量</th><th style="text-align:left;">備考</th></tr></thead><tbody><tr><td style="text-align:center;">1時間</td><td style="text-align:left;">少量</td><td style="text-align:left;">短時間で回収可能</td></tr><tr><td style="text-align:center;">4時間</td><td style="text-align:left;">中量</td><td style="text-align:left;">バランス型</td></tr><tr><td style="text-align:center;">8時間</td><td style="text-align:left;">多量</td><td style="text-align:left;">就寝前に推奨</td></tr><tr><td style="text-align:center;">12時間</td><td style="text-align:left;">大量</td><td style="text-align:left;">最高効率</td></tr></tbody></table><ul><li>派遣にはキャラクターのレアリティが高いほど追加ボーナス</li><li>特定の属性と派遣先の組み合わせでボーナス報酬</li><li>派遣中のキャラクターは戦闘にも使用可能（他ゲームと異なる）</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>派遣報酬は回収しないと蓄積上限に達して生産が停止します。こまめにログインして回収しましょう。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./affinity.html">好感度システム</a></li><li><a href="./../guides/dailies.html">デイリータスク</a></li><li><a href="./../items/">アイテム概要</a></li></ul>',22)])])}const o=e(i,[["render",n]]);export{g as __pageData,o as default};
